def bash_exec(command: str, timeout: int = None) -> str:
    try:
        t = int(timeout) if timeout else config.BASH_TIMEOUT
        t = min(t, config.BASH_TIMEOUT_MAX)
        result = subprocess.run(
            command, shell=True, cwd=config.WORKSPACE_DIR,
            capture_output=True, text=True, timeout=t,
        )
        out = result.stdout[-4000:]
        err = result.stderr[-2000:]
        return f"[exit={result.returncode}]\nSTDOUT:\n{out}\nSTDERR:\n{err}"
    except subprocess.TimeoutExpired:
        return "[error] command timeout"
    except Exception as e:
        return f"[error] {e}"


def install_package(manager: str, package: str) -> str:
    cmds = {
        "pip": f"pip install --break-system-packages {package}",
        "npm": f"npm install -g {package}",
        "pkg": f"pkg install -y {package}",
    }
    cmd = cmds.get(manager)
    if not cmd:
        return f"[error] manager '{manager}' tidak dikenal"
    return bash_exec(cmd)


def write_file(path: str, content: str) -> str:
    try:
        full = _safe_path(path)
        os.makedirs(os.path.dirname(full), exist_ok=True)
        with open(full, "w") as f:
            f.write(content)
        return f"[ok] file ditulis: {path} ({len(content)} bytes)"
    except Exception as e:
        return f"[error] {e}"


def patch_file(path: str, old_str: str, new_str: str) -> str:
    try:
        full = _safe_path(path)
        with open(full, "r") as f:
            content = f.read()
        count = content.count(old_str)
        if count == 0:
            return "[error] old_str tidak ditemukan persis di file. Cek ulang spasi/indentasi."
        if count > 1:
            return f"[error] old_str muncul {count} kali, harus unik. Perjelas konteks (tambah baris sekitar)."
        new_content = content.replace(old_str, new_str)
        with open(full, "w") as f:
            f.write(new_content)
        return f"[ok] file dipatch: {path}"
    except Exception as e:
        return f"[error] {e}"


def read_file(path: str, start_line: int = None, num_lines: int = None) -> str:
    try:
        full = _safe_path(path)
        with open(full, "r") as f:
            content = f.read()
        lines = content.split("\n")
        total_lines = len(lines)

        if start_line is not None:
            start_idx = max(0, int(start_line) - 1)
            n = int(num_lines) if num_lines else DEFAULT_CHUNK_LINES
            selected = lines[start_idx:start_idx + n]
            end_line = start_idx + len(selected)
            header = f"[baris {start_idx + 1}-{end_line} dari {total_lines} total baris]\n"
            return header + "\n".join(selected)

        if len(content) > READ_FILE_LIMIT:
            truncated = content[:READ_FILE_LIMIT]
            sisa = len(content) - READ_FILE_LIMIT
            return (
                f"{truncated}\n\n[...dipotong, {sisa} karakter lagi ({total_lines} baris total). "
                f"Pakai start_line+num_lines buat baca bagian tertentu...]"
            )
        return content
    except Exception as e:
        return f"[error] {e}"


def list_dir(path: str = ".") -> str:
    try:
        full = _safe_path(path)
        return "\n".join(os.listdir(full))
    except Exception as e:
        return f"[error] {e}"


